package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsQuoteCharacterSet() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set quoteCharacter to null
        when(csvFormat.getQuoteCharacter()).thenReturn(null);

        // Test when quoteCharacter is null
        assertFalse(csvFormat.isQuoteCharacterSet());

        // Set quoteCharacter to a valid character
        when(csvFormat.getQuoteCharacter()).thenReturn('"');

        // Test when quoteCharacter is not null
        assertTrue(csvFormat.isQuoteCharacterSet());
    }
}
